import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Invalid Grant 排查: 帳號停用恢復 | Antigravity-Manager","description":"學習 invalid_grant 錯誤的含義與自動處理邏輯。確認 refresh_token 失效後，透過重新 OAuth 新增帳號觸發自動解禁，並驗證恢復對 Proxy 生效。","frontmatter":{"title":"Invalid Grant 排查: 帳號停用恢復 | Antigravity-Manager","sidebarTitle":"帳號被停用了怎麼恢復","subtitle":"invalid_grant 與帳號自動停用：為什麼會發生、如何恢復","description":"學習 invalid_grant 錯誤的含義與自動處理邏輯。確認 refresh_token 失效後，透過重新 OAuth 新增帳號觸發自動解禁，並驗證恢復對 Proxy 生效。","tags":["FAQ","錯誤排查","OAuth","帳號管理","invalid_grant"],"prerequisite":["../../start/add-account/","../../start/first-run-data/","../../advanced/scheduling/"],"order":1},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),o={name:"zh-tw/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function d(n,a,s,l,c,h){return r(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="invalid-grant-與帳號自動停用-為什麼會發生、如何恢復" tabindex="-1">invalid_grant 與帳號自動停用：為什麼會發生、如何恢復 <a class="header-anchor" href="#invalid-grant-與帳號自動停用-為什麼會發生、如何恢復" aria-label="Permalink to &quot;invalid_grant 與帳號自動停用：為什麼會發生、如何恢復&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>看到 <code>invalid_grant</code> 時，知道它對應的是哪一類 refresh_token 問題</li><li>搞清楚「帳號為什麼突然不可用」：什麼情況下會被自動停用、停用後系統怎麼處理</li><li>用最短路徑恢復帳號，並確認恢復已經對正在執行的 Proxy 生效</li></ul><h2 id="你遇到的症狀" tabindex="-1">你遇到的症狀 <a class="header-anchor" href="#你遇到的症狀" aria-label="Permalink to &quot;你遇到的症狀&quot;">​</a></h2><ul><li>呼叫本機 Proxy 時突然失敗，錯誤資訊裡出現 <code>invalid_grant</code></li><li>明明帳號還在 Accounts 清單裡，但 Proxy 總是跳過它（或者你覺得它「再也沒被用到」）</li><li>只有少量帳號時，遇到一次 <code>invalid_grant</code> 後，整體可用性明顯變差</li></ul><h2 id="什麼是-invalid-grant" tabindex="-1">什麼是 invalid_grant？ <a class="header-anchor" href="#什麼是-invalid-grant" aria-label="Permalink to &quot;什麼是 invalid_grant？&quot;">​</a></h2><p><strong>invalid_grant</strong> 是 Google OAuth 在重新整理 <code>access_token</code> 時傳回的一類錯誤。對 Antigravity Tools 來說，它意味著某個帳號的 <code>refresh_token</code> 很可能已經被撤銷或過期，繼續重試只會反覆失敗，所以系統會把該帳號標記為不可用並從代理池中移出。</p><h2 id="核心思路-系統不是「暫時跳過」-而是「持久停用」" tabindex="-1">核心思路：系統不是「暫時跳過」，而是「持久停用」 <a class="header-anchor" href="#核心思路-系統不是「暫時跳過」-而是「持久停用」" aria-label="Permalink to &quot;核心思路：系統不是「暫時跳過」，而是「持久停用」&quot;">​</a></h2><p>當 Proxy 發現重新整理 token 的錯誤字串包含 <code>invalid_grant</code> 時，會做兩件事：</p><ol><li><strong>把帳號寫成 disabled</strong>（落盤到帳號 JSON）</li><li><strong>把帳號從記憶體 token pool 移除</strong>（避免反覆選中同一個壞帳號）</li></ol><p>這就是你看到「帳號還在，但 Proxy 不再用它」的原因。</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>：帳號被「徹底停用」（典型原因就是 <code>invalid_grant</code>）。載入帳號池時會直接跳過。</li><li><code>proxy_disabled=true</code>：帳號只是「對 Proxy 不可用」（手動停用/批次操作/配額保護相關邏輯），語意不同。</li></ul><p>這兩個狀態在載入帳號池時是分開判斷的：先判斷 <code>disabled</code>，再做配額保護與 <code>proxy_disabled</code> 判斷。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-確認是不是-refresh-token-重新整理觸發的-invalid-grant" tabindex="-1">第 1 步：確認是不是 refresh_token 重新整理觸發的 invalid_grant <a class="header-anchor" href="#第-1-步-確認是不是-refresh-token-重新整理觸發的-invalid-grant" aria-label="Permalink to &quot;第 1 步：確認是不是 refresh_token 重新整理觸發的 invalid_grant&quot;">​</a></h3><p><strong>為什麼</strong>：<code>invalid_grant</code> 可能出現在多個呼叫鏈路裡，但本專案的「自動停用」只在<strong>重新整理 access_token 失敗</strong>時觸發。</p><p>在 Proxy 日誌裡，你會看到類似的錯誤日誌（關鍵字是 <code>Token 重新整理失敗</code> + <code>invalid_grant</code>）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 重新整理失敗 (&lt;email&gt;): &lt;...invalid_grant...&gt;，嘗試下一個帳號</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>你應該看到</strong>：同一個帳號在出現 <code>invalid_grant</code> 後，很快就不再被選中（因為它被移出 token pool）。</p><h3 id="第-2-步-在帳號檔案裡檢查-disabled-欄位-可選-但最準確" tabindex="-1">第 2 步：在帳號檔案裡檢查 disabled 欄位（可選，但最準確） <a class="header-anchor" href="#第-2-步-在帳號檔案裡檢查-disabled-欄位-可選-但最準確" aria-label="Permalink to &quot;第 2 步：在帳號檔案裡檢查 disabled 欄位（可選，但最準確）&quot;">​</a></h3><p><strong>為什麼</strong>：自動停用是「落盤」的，你確認檔案內容後，就能排除「只是暫時輪換」的誤判。</p><p>帳號檔案位於應用程式資料目錄的 <code>accounts/</code> 目錄下（資料目錄位置見 <strong><a href="./../../start/first-run-data/">首次啟動必懂：資料目錄、日誌、系統匣與自動啟動</a></strong>）。當帳號被停用時，檔案會出現這三個欄位：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你應該看到</strong>：<code>disabled</code> 為 <code>true</code>，並且 <code>disabled_reason</code> 裡包含 <code>invalid_grant:</code> 前綴。</p><h3 id="第-3-步-恢復帳號-推薦做法-重新新增同一個帳號" tabindex="-1">第 3 步：恢復帳號（推薦做法：重新新增同一個帳號） <a class="header-anchor" href="#第-3-步-恢復帳號-推薦做法-重新新增同一個帳號" aria-label="Permalink to &quot;第 3 步：恢復帳號（推薦做法：重新新增同一個帳號）&quot;">​</a></h3><p><strong>為什麼</strong>：本專案的「恢復」不是在 Proxy 裡手動點一個開關，而是透過「明確更新 token」來觸發自動解禁。</p><p>到 <strong>Accounts</strong> 頁面，用你新的憑證重新新增帳號（兩種方式任選其一）：</p><ol><li>重新走 OAuth 授權流程（見 <strong><a href="./../../start/add-account/">新增帳號：OAuth/Refresh Token 雙通道與最佳實務</a></strong>）</li><li>用新的 <code>refresh_token</code> 再新增一次（系統會以 Google 傳回的電子郵件為準做 upsert）</li></ol><p>當系統偵測到你這次 upsert 的 <code>refresh_token</code> 或 <code>access_token</code> 與舊值不同，並且該帳號之前處於 <code>disabled=true</code>，會自動清掉：</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>你應該看到</strong>：帳號不再處於 disabled 狀態，並且（如果 Proxy 正在執行）帳號池會被自動 reload，讓恢復立即生效。</p><h3 id="第-4-步-驗證恢復是否已對-proxy-生效" tabindex="-1">第 4 步：驗證恢復是否已對 Proxy 生效 <a class="header-anchor" href="#第-4-步-驗證恢復是否已對-proxy-生效" aria-label="Permalink to &quot;第 4 步：驗證恢復是否已對 Proxy 生效&quot;">​</a></h3><p><strong>為什麼</strong>：如果你只有一個帳號，或者其他帳號也不可用，恢復後你應該立刻看到「可用性回來了」。</p><p>驗證方法：</p><ol><li>發起一次會觸發 token 重新整理的請求（例如等待 token 臨近過期後再請求）</li><li>觀察日誌不再出現「跳過 disabled 帳號」的提示</li></ol><p><strong>你應該看到</strong>：請求能正常通過，且日誌裡不再出現針對該帳號的 <code>invalid_grant</code> 停用流程。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-把-disabled-當成「暫時輪換」" tabindex="-1">❌ 把 disabled 當成「暫時輪換」 <a class="header-anchor" href="#❌-把-disabled-當成「暫時輪換」" aria-label="Permalink to &quot;❌ 把 disabled 當成「暫時輪換」&quot;">​</a></h3><p>如果你只在 UI 裡看「帳號還在」，很容易誤判為「系統只是暫時不用它」。但 <code>disabled=true</code> 是寫到磁碟上的，重新啟動後也會繼續生效。</p><h3 id="❌-只補充-access-token-不更新-refresh-token" tabindex="-1">❌ 只補充 access_token，不更新 refresh_token <a class="header-anchor" href="#❌-只補充-access-token-不更新-refresh-token" aria-label="Permalink to &quot;❌ 只補充 access_token，不更新 refresh_token&quot;">​</a></h3><p><code>invalid_grant</code> 的觸發點是重新整理 <code>access_token</code> 時使用的 <code>refresh_token</code>。如果你只是暫時拿到了一個還能用的 <code>access_token</code>，但 <code>refresh_token</code> 依舊失效，後續還是會再次觸發停用。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>[ ] 你能在日誌裡確認 <code>invalid_grant</code> 來自 refresh_token 重新整理失敗</li><li>[ ] 你知道 <code>disabled</code> 和 <code>proxy_disabled</code> 的語意差異</li><li>[ ] 你能透過重新新增帳號（OAuth 或 refresh_token）恢復帳號</li><li>[ ] 你能驗證恢復已經對執行中的 Proxy 生效</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li><code>invalid_grant</code> 觸發時，Proxy 會把帳號 <strong>落盤為 disabled</strong>，並從 token pool 移除，避免反覆失敗</li><li>恢復的關鍵是「明確更新 token」（重新 OAuth 或用新 refresh_token 再新增一次），系統會自動清掉 <code>disabled_*</code> 欄位</li><li>資料目錄中的帳號 JSON 是最權威的狀態來源（停用/原因/時間都在裡面）</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../auth-401/">401/鑑權失敗：auth_mode、Header 相容與客戶端設定清單</a></strong>。</p><p>你會學到：</p><ul><li>401 通常是「模式/Key/Header」哪一層不匹配</li><li>不同客戶端該帶什麼鑑權 Header</li><li>如何用最短路徑自檢並修復</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>設計說明：invalid_grant 的問題與變更行為</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>載入帳號池時跳過 <code>disabled=true</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>重新整理 token 失敗時識別 <code>invalid_grant</code> 並停用帳號</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td>持久化寫入 <code>disabled/disabled_at/disabled_reason</code> 並從記憶體移除</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td><code>disabled_reason</code> 截斷（避免帳號檔案膨脹）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>upsert 時自動清理 <code>disabled_*</code>（token 變化即視為使用者已修復憑證）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>重新新增帳號後自動 reload proxy accounts（執行中立即生效）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const u=e(o,[["render",d]]);export{p as __pageData,u as default};
